sql:
SELECT review_rating, review_comment 
FROM course_reviews 
WHERE student_id = 1 AND course_id = 0;

SELECT c.course_name, cr.review_rating, cr.review_comment
FROM courses c
JOIN course_reviews cr ON c.course_id = cr.course_id;

SELECT module_name 
FROM modules 
WHERE module_id = 0;

SELECT course_name, program, start_year
FROM courses
WHERE course_id NOT IN (
    SELECT course_id 
    FROM course_reviews
);

SELECT COUNT(*) 
FROM student_assessments
WHERE module_assessment_id = 1 AND assessment_result >= 90;

SELECT AVG(grade) AS average_grade
FROM grades
WHERE student_id = 1;

SELECT course_name, start_year 
FROM courses 
ORDER BY start_year DESC;

external_knowledge:
- 'excelled' refers to achieving grades greater than 80;
- 'outstanding average performance' means having an average grade over 85;
- 'theoretical modules' refers to modules with the 'module_type' set to 'theoretical'.
